def {{nama_fungsi}}(response_text):
    """Ambil objek JSON pertama dari response_text lalu validasi key wajib."""
    match = re.search(r"\{.*\}", response_text, re.DOTALL)
    if not match:
        raise ValueError("Tidak ditemukan objek JSON dalam respons")
    data = json.loads(match.group())
    required = {{expected_keys}}
    missing = [k for k in required if k not in data]
    if missing:
        raise KeyError(f"Field wajib hilang: {missing}")
    return data

def {{nama_fungsi}}(data, schema):
    """schema: dict {nama_key: tipe_python}. Kembalikan True jika valid, lempar ValueError jika tidak."""
    if not isinstance(data, dict):
        raise ValueError("Output bukan dict")
    for key, expected_type in schema.items():
        if key not in data:
            raise ValueError(f"Key '{key}' tidak ditemukan pada output")
        if not isinstance(data[key], expected_type):
            raise ValueError(
                f"Key '{key}' harus bertipe {expected_type.__name__}, "
                f"didapat {type(data[key]).__name__}"
            )
    return True

def {{nama_fungsi}}(caller_func, parser_func, *args, **kwargs):
    """Panggil caller_func lalu proses hasilnya lewat parser_func.
    Ulangi sampai {{max_attempts}}x jika parser_func melempar exception."""
    last_error = None
    for attempt in range(1, {{max_attempts}} + 1):
        raw_output = caller_func(*args, **kwargs)
        try:
            return parser_func(raw_output)
        except Exception as e:
            last_error = e
    raise ValueError(f"Gagal mendapat output valid setelah {{max_attempts}} percobaan: {last_error}")
